SELECT country_id, SUM(cumulative_total) AS total_tests_conducted
FROM covid_testing_data
GROUP BY country_id;

SELECT cumulative_total, recovery_rate
FROM covid_testing_data
ORDER BY cumulative_total DESC;

SELECT country_id, SUM(total_tests) AS total_tests_sum, AVG(average_tests_per_day) AS average_tests_avg
FROM aggregated_testing_data
GROUP BY country_id;

SELECT SUM(positive_cases) AS total_positive_cases, AVG(recovery_rate) AS average_recovery_rate
FROM covid_testing_data
WHERE country_id = 1;

SELECT date, cumulative_total
FROM covid_testing_data
ORDER BY date DESC;

SELECT date, cumulative_total
FROM covid_testing_data
WHERE cumulative_total > 10000;

SELECT cumulative_total
FROM covid_testing_data
WHERE date = (SELECT MAX(date) FROM covid_testing_data);
